// MARK: - Network Service

class NetworkService: NSObject {
    static let shared = NetworkService()
    
    private var secureSession: URLSession!
    private var insecureSession: URLSession!
    
    private override init() {
        super.init()
        
        // Secure session for production API
        let secureConfig = URLSessionConfiguration.default
        secureConfig.timeoutIntervalForRequest = 30
        secureConfig.timeoutIntervalForResource = 60
        secureConfig.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        secureSession = URLSession(configuration: secureConfig, delegate: self, delegateQueue: nil)
        
        // Insecure session for legacy systems
        let insecureConfig = URLSessionConfiguration.default
        insecureConfig.timeoutIntervalForRequest = 45
        insecureConfig.timeoutIntervalForResource = 90
        insecureConfig.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        insecureSession = URLSession(configuration: insecureConfig, delegate: self, delegateQueue: nil)
    }
    
    private func session(for environment: APIEnvironment) -> URLSession {
        switch environment {
        case .production:
            return secureSession
        case .legacy:
            return insecureSession
        }
    }
    
    // MARK: - Generic Request Method
    
    func request<T: Codable>(
        environment: APIEnvironment,
        path: String,
        method: String = "GET",
        body: Data? = nil,
        headers: [String: String]? = nil,
        completion: @escaping (Result<T, NetworkError>) -> Void
    ) {
        let urlString = "\(environment.baseURL)\(path)"
        
        guard let url = URL(string: urlString) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.httpBody = body
        
        headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        let urlSession = session(for: environment)
        
        let task = urlSession.dataTask(with: request) { data, response, error in
            if let error = error {
                let nsError = error as NSError
                // Check if ATS blocked the connection
                if nsError.domain == NSURLErrorDomain &&
                    (nsError.code == NSURLErrorAppTransportSecurityRequiresSecureConnection ||
                     nsError.code == NSURLErrorSecureConnectionFailed) {
                    DispatchQueue.main.async {
                        completion(.failure(.atsBlocked))
                    }
                    return
                }
                DispatchQueue.main.async {
                    completion(.failure(.networkFailure(error)))
                }
                return
            }
            
            if let httpResponse = response as? HTTPURLResponse,
               !(200...299).contains(httpResponse.statusCode) {
                DispatchQueue.main.async {
                    completion(.failure(.serverError(httpResponse.statusCode)))
                }
                return
            }
            
            guard let data = data else {
                DispatchQueue.main.async {
                    completion(.failure(.noData))
                }
                return
            }
            
            do {
                let decoded = try JSONDecoder().decode(T.self, from: data)
                DispatchQueue.main.async {
                    completion(.success(decoded))
                }
            } catch {
                DispatchQueue.main.async {
                    completion(.failure(.decodingError(error)))
                }
            }
        }
        
        task.resume()
    }
    
    // MARK: - Async/Await Support
    
    @available(iOS 13.0, *)
    func request<T: Codable>(
        environment: APIEnvironment,
        path: String,
        method: String = "GET",
        body: Data? = nil,
        headers: [String: String]? = nil
    ) async throws -> T {
        let urlString = "\(environment.baseURL)\(path)"
        
        guard let url = URL(string: urlString) else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.httpBody = body
        
        headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        let urlSession = session(for: environment)
        
        do {
            let (data, response) = try await urlSession.data(for: request)
            
            if let httpResponse = response as? HTTPURLResponse,
               !(200...299).contains(httpResponse.statusCode) {
                throw NetworkError.serverError(httpResponse.statusCode)
            }
            
            let decoded = try JSONDecoder().decode(T.self, from: data)
            return decoded
        } catch let error as NetworkError {
            throw error
        } catch let error as NSError where error.domain == NSURLErrorDomain &&
            (error.code == NSURLErrorAppTransportSecurityRequiresSecureConnection ||
             error.code == NSURLErrorSecureConnectionFailed) {
            throw NetworkError.atsBlocked
        } catch {
            throw NetworkError.networkFailure(error)
        }
    }
}

// MARK: - URLSessionDelegate for SSL/TLS handling

extension NetworkService: URLSessionDelegate {
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        let host = challenge.protectionSpace.host
        
        if challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust {
            if let serverTrust = challenge.protectionSpace.serverTrust {
                // For production API - enforce strict SSL validation
                if host.contains("api.example.com") {
                    completionHandler(.performDefaultHandling, nil)
                    return
                }
                
                // For legacy internal systems - allow the connection
                // (ATS exception in Info.plist handles the HTTP allowance)
                if host.contains("legacy.internal") {
                    let credential = URLCredential(trust: serverTrust)
                    completionHandler(.useCredential, credential)
                    return
                }
            }
        }
        
        completionHandler(.performDefaultHandling, nil)
    }
}

// MARK: - API Service Layer

class ProductionAPIService {
    private let network = NetworkService.shared
    
    func fetchUsers(completion: @escaping (Result<APIResponse<[APIUser]>, NetworkError>) -> Void) {
        network.request(
            environment: .production,
            path: "/v1/users",
            completion: completion
        )
    }
    
    func fetchUser(id: Int, completion: @escaping (Result<APIResponse<APIUser>, NetworkError>) -> Void) {
        network.request(
            environment: .production,
            path: "/v1/users/\(id)",
            completion: completion
        )
    }
    
    func createUser(name: String, email: String, completion: @escaping (Result<APIResponse<APIUser>, NetworkError>) -> Void) {
        let body: [String: Any] = ["name": name, "email": email]
        let bodyData = try? JSONSerialization.data(withJSONObject: body)
        
        network.request(
            environment: .production,
            path: "/v1/users",
            method: "POST",
            body: bodyData,
            completion: completion
        )
    }
    
    @available(iOS 13.0, *)
    func fetchUsersAsync() async throws -> APIResponse<[APIUser]> {
        try await network.request(
            environment: .production,
            path: "/v1/users"
        )
    }
}

class LegacyAPIService {
    private let network = NetworkService.shared
    
    func fetchRecords(completion: @escaping (Result<[LegacyRecord], NetworkError>) -> Void) {
        network.request(
            environment: .legacy,
            path: "/api/records",
            completion: completion
        )
    }
    
    func fetchRecord(id: String, completion: @escaping (Result<LegacyRecord, NetworkError>) -> Void) {
        network.request(
            environment: .legacy,
            path: "/api/records/\(id)",
            completion: completion
        )
    }
    
    func syncRecord(record: LegacyRecord, completion: @escaping (Result<LegacyRecord, NetworkError>) -> Void) {
        let bodyData = try? JSONEncoder().encode(record)
        
        network.request(
            environment: .legacy,
            path: "/api/records/sync",
            method: "POST",
            body: bodyData,
            completion: completion
        )
    }
    
    @available(iOS 13.0, *)
    func fetchRecordsAsync() async throws -> [LegacyRecord] {
        try await network.request(
            environment: .legacy,
            path: "/api/records"
        )
    }
}

// MARK: - ATS Diagnostics Utility

class ATSDiagnostics {
    static func checkATSConfiguration() {
        guard let infoDict = Bundle.main.infoDictionary,
              let atsDict = infoDict["NSAppTransportSecurity"] as? [String: Any] else {
            print("⚠️ No ATS configuration found in Info.plist")
            return
        }
        
        let arbitraryLoads = atsDict["NSAllowsArbitraryLoads"] as? Bool ?? false
        print("🔐 ATS Configuration:")
        print("   Arbitrary Loads: \(arbitraryLoads ? "ENABLED ⚠️" : "DISABLED ✅")")
        
        if let exceptions = atsDict["NSExceptionDomains"] as? [String: Any] {
            print("   Exception Domains:")
            for (domain, config) in exceptions {
                if let domainConfig = config as? [String: Any] {
                    let allowsInsecure = domainConfig["NSExceptionAllowsInsecureHTTPLoads"] as? Bool ?? false
                    let includesSubdomains = domainConfig["NSIncludesSubdomains"] as? Bool ?? false
                    let forwardSecrecy = domainConfig["NSExceptionRequiresForwardSecrecy"] as? Bool ?? true
                    
                    print("   - \(domain):")
                    print("     Allows Insecure HTTP: \(allowsInsecure)")
                    print("     Includes Subdomains: \(includesSubdomains)")
                    print("     Requires Forward Secrecy: \(forwardSecrecy)")
                }
            }
        }
    }
    
    static func testConnectivity(completion: @escaping (String) -> Void) {
        var results = ""
        let group = DispatchGroup()
        
        // Test production API
        group.enter()
        if let url = URL(string: "https://api.example.com/health") {
            URLSession.shared.dataTask(with: url) { _, response, error in
                if let error = error {
                    results += "❌ Production API: \(error.localizedDescription)\n"
                } else if let httpResponse = response as? HTTPURLResponse {
                    results += "✅ Production API: HTTP \(httpResponse.statusCode)\n"
                }
                group.leave()
            }.resume()
        } else {
            results += "❌ Production API: Invalid URL\n"
            group.leave()
        }
        
        // Test legacy system
        group.enter()
        if let url = URL(string: "http://legacy.internal/api/health") {
            URLSession.shared.dataTask(with: url) { _, response, error in
                if let error = error {
                    let nsError = error as NSError
                    if nsError.code == NSURLErrorAppTransportSecurityRequiresSecureConnection {
                        results += "🔒 Legacy System: Blocked by ATS - Check exceptions\n"
                    } else {
                        results += "❌ Legacy System: \(error.localizedDescription)\n"
                    }
                } else if let httpResponse = response as? HTTPURLResponse {
                    results += "✅ Legacy System: HTTP \(httpResponse.statusCode)\n"
                }
                group.leave()
            }.resume()
        } else {
            results += "❌ Legacy System: Invalid URL\n"
            group.leave()
        }
        
        group.notify(queue: .main) {
            completion(results)
        }
    }
}

