    @objc private func testProductionAPI() {
        statusLabel.text = "Testing Production API (HTTPS)..."
        activityIndicator.startAnimating()
        resultTextView.text = ""
        
        productionAPI.fetchUsers { [weak self] result in
            self?.activityIndicator.stopAnimating()
            switch result {
            case .success(let response):
                self?.statusLabel.text = "✅ Production API Connected"
                self?.resultTextView.text = """
                Production API Response:
                Success: \(response.success)
                Message: \(response.message ?? "N/A")
                Users: \(response.data?.count ?? 0) found
                
                Connection: HTTPS (TLS 1.2+)
                Domain: api.example.com
                ATS: Standard secure connection
                """
            case .failure(let error):
                self?.statusLabel.text = "❌ Production API Error"
                self?.resultTextView.text = """
                Production API Error:
                \(error.localizedDescription)
                
                Connection: HTTPS (TLS 1.2+)
                Domain: api.example.com
                
                Note: This is expected if the server is not reachable.
                ATS is configured to enforce HTTPS for this domain.
                """
            }
        }
    }
    
    @objc private func testLegacyAPI() {
        statusLabel.text = "Testing Legacy System (HTTP)..."
        activityIndicator.startAnimating()
        resultTextView.text = ""
        
        legacyAPI.fetchRecords { [weak self] result in
            self?.activityIndicator.stopAnimating()
            switch result {
            case .success(let records):
                self?.statusLabel.text = "✅ Legacy System Connected"
                self?.resultTextView.text = """
                Legacy System Response:
                Records: \(records.count) found
                
                Connection: HTTP (Insecure)
                Domain: legacy.internal
                ATS Exception: NSExceptionAllowsInsecureHTTPLoads = true
                
                ⚠️ This connection is NOT encrypted.
                Only use for trusted internal networks.
                """
            case .failure(let error):
                self?.statusLabel.text = "❌ Legacy System Error"
                var atsNote = ""
                if case .atsBlocked = error {
                    atsNote = """
                    
                    🔒 ATS BLOCKED THIS CONNECTION!
                    Ensure Info.plist has the exception for legacy.internal:
                    - NSExceptionAllowsInsecureHTTPLoads: YES
                    - NSIncludesSubdomains: YES
                    """
                }
                self?.resultTextView.text = """
                Legacy System Error:
                \(error.localizedDescription)
                
                Connection: HTTP (Insecure)
                Domain: legacy.internal
                \(atsNote)
                
                Note: This is expected if the legacy server is not reachable.
                ATS is configured to allow HTTP for this domain via exceptions.
                """
            }
        }
    }
    
    @objc private func runDiagnostics() {
        statusLabel.text = "Running ATS Diagnostics..."
        
        var diagnosticText = "🔐 ATS Diagnostics Report\n"
        diagnosticText += "========================\n\n"
        
        if let infoDict = Bundle.main.infoDictionary,
           let atsDict = infoDict["NSAppTransportSecurity"] as? [String: Any] {
            
            let arbitraryLoads = atsDict["NSAllowsArbitraryLoads"] as? Bool ?? false
            diagnosticText += "Global Settings:\n"
            diagnosticText += "  Arbitrary Loads: \(arbitraryLoads ? "⚠️ ENABLED" : "✅ DISABLED")\n\n"
            
            if let exceptions = atsDict["NSExceptionDomains"] as? [String: Any] {
                diagnosticText += "Exception Domains:\n"
                for (domain, config) in exceptions {
                    if let domainConfig = config as? [String: Any] {
                        let allowsInsecure = domainConfig["NSExceptionAllowsInsecureHTTPLoads"] as? Bool ?? false
                        let includesSubdomains = domainConfig["NSIncludesSubdomains"] as? Bool ?? false
                        let forwardSecrecy = domainConfig["NSExceptionRequiresForwardSecrecy"] as? Bool ?? true
                        let minTLS = domainConfig["NSTemporaryExceptionMinimumTLSVersion"] as? String
                            ?? domainConfig["NSExceptionMinimumTLSVersion"] as? String
                            ?? "Default"
                        
                        diagnosticText += "\n  📌 \(domain)\n"
                        diagnosticText += "    HTTP Allowed: \(allowsInsecure ? "⚠️ YES" : "✅ NO")\n"
                        diagnosticText += "    Subdomains: \(includesSubdomains ? "YES" : "NO")\n"
                        diagnosticText += "    Forward Secrecy: \(forwardSecrecy ? "YES" : "NO")\n"
                        diagnosticText += "    Min TLS: \(minTLS)\n"
                    }
                }
            }
        } else {
            diagnosticText += "⚠️ No ATS configuration found in Info.plist\n"
            diagnosticText += "Default ATS rules apply (HTTPS required for all connections)\n"
        }
        
        diagnosticText += "\n\nExpected Configuration:\n"
        diagnosticText += "  api.example.com → HTTPS only, TLS 1.2+\n"
        diagnosticText += "  legacy.internal → HTTP allowed (ATS exception)\n"
        
        resultTextView.text = diagnosticText
        statusLabel.text = "✅ Diagnostics Complete"
    }
    
    @objc private func testConnectivity() {
        statusLabel.text = "Testing connectivity to all endpoints..."
        activityIndicator.startAnimating()
        resultTextView.text = ""
        
        ATSDiagnostics.testConnectivity { [weak self] results in
            self?.activityIndicator.stopAnimating()
            self?.statusLabel.text = "Connectivity Test Complete"
            self?.resultTextView.text = """
            🌐 Connectivity Test Results
            ============================
            
            \(results)
            
            Configuration Summary:
            • api.example.com: HTTPS enforced by ATS
            • legacy.internal: HTTP allowed via ATS exception
            
            If legacy.internal shows "Blocked by ATS":
            Verify Info.plist contains the exception domain
            with NSExceptionAllowsInsecureHTTPLoads = true
            """
        }
    }
}

// MARK: - App Delegate

@UIApplicationMain
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(
        _ application: UIApplication,
        didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?
    ) -> Bool {
        
        window = UIWindow(frame: UIScreen.main.bounds)
        let viewController = ViewController()
        let navigationController = UINavigationController(rootViewController: viewController)
        window?.rootViewController = navigationController
        window?.makeKeyAndVisible()
        
        // Log ATS configuration on startup
        print("========================================")
        print("App Transport Security Configuration")
        print("========================================")
        ATSDiagnostics.checkATSConfiguration()
        print("========================================")
        
        return true
    }
}